			WithLogger(s.logger).
			WithDatacenter(s.config.Datacenter).
			WithDisabledTenancyMetrics(s.config.DisablePerTenancyUsageMetrics).
			WithReportingInterval(s.config.MetricsReportingInterval).
			WithGetMembersFunc(func() []serf.Member {
